```bash
sed -i '7435,7442c\  if (!(BestFactor.Width == LegacyVF.Width ||
        planContainsAdditionalSimplifications(getPlanFor(BestFactor.Width),
                                              CostCtx, OrigLoop))) {
    LLVM_DEBUG(dbgs() << "LV: VPlan and legacy cost models disagreed; preferring legacy VF to avoid crash.\n");
    BestFactor = LegacyVF;
  }' /llvm-autofix-deps/llvm/llvm/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp && cd /llvm-autofix/build/llvm-build/111874 && ninja opt && /llvm-autofix/build/llvm-build/111874/bin/opt -p loop-vectorize -S /tmp/test.ll
